import React, { useState, useRef } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { TrendingUp, TrendingDown, Trash2 } from 'lucide-react';

const App = () => {
  const [page, setPage] = useState('landing');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [activeTab, setActiveTab] = useState('screener');
  const [scanInput, setScanInput] = useState('AAPL,MSFT,GOOGL,TSLA,NVDA,AMD,PLTR,SOFI');
  const [scanResults, setScanResults] = useState([]);
  const [selectedStock, setSelectedStock] = useState(null);
  const [loading, setLoading] = useState(false);
  const [watchlist, setWatchlist] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [selectedFilter, setSelectedFilter] = useState('all');
  const [chartData, setChartData] = useState([]);
  const [lines, setLines] = useState([]);
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawMode, setDrawMode] = useState(null);
  const canvasRef = useRef(null);
  const [startPoint, setStartPoint] = useState(null);

  const generateAdvancedData = (ticker) => ({
    ticker: ticker.toUpperCase(),
    price: (Math.random() * 200 + 20).toFixed(2),
    change: ((Math.random() - 0.5) * 30).toFixed(2),
    percentChange: ((Math.random() - 0.5) * 15).toFixed(2),
    volume: (Math.random() * 100000000).toFixed(0),
    rsi: (Math.random() * 100).toFixed(1),
    signal: (Math.random() * 100).toFixed(0),
    pe_ratio: (Math.random() * 40 + 5).toFixed(2),
    earnings_date: '2026-' + (Math.floor(Math.random() * 8) + 1).toString().padStart(2, '0') + '-' + Math.floor(Math.random() * 28 + 1).toString().padStart(2, '0'),
    dividend_yield: (Math.random() * 8).toFixed(2),
    dayHigh: (Math.random() * 200 + 100).toFixed(2),
    dayLow: (Math.random() * 100 + 50).toFixed(2),
    gapUp: Math.random() > 0.7,
    volumeSpike: Math.random() > 0.6,
    breakout: Math.random() > 0.5,
    oversold: parseFloat((Math.random() * 100).toFixed(1)) < 30,
  });

  const generateChartData = () => {
    return Array.from({ length: 48 }, (_, i) => ({
      time: `${Math.floor(i / 2)}:${(i % 2) * 30}`,
      price: Math.random() * 50 + 100,
      volume: Math.random() * 1000000
    }));
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const url = isSignUp ? 'http://localhost:5001/api/auth/register' : 'http://localhost:5001/api/auth/login';
      const res = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(isSignUp ? { email, password, name } : { email, password }) });
      const data = await res.json();
      if (data.token) {
        localStorage.setItem('token', data.token);
        setIsLoggedIn(true);
        setPage('app');
      } else {
        alert('Error: ' + (data.error || 'Failed'));
      }
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  const handleScan = async (e) => {
    e.preventDefault();
    setLoading(true);
    const tickers = scanInput.split(',').map(t => t.trim());
    const token = localStorage.getItem('token');
    try {
      const res = await fetch('http://localhost:5001/api/scan', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token }, body: JSON.stringify({ tickers }) });
      const data = await res.json();
      const enhanced = (data.results || []).map(r => ({ ...r, ...generateAdvancedData(r.ticker) }));
      setScanResults(enhanced);
      setSelectedStock(null);
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  const toggleWatchlist = (ticker) => {
    if (watchlist.includes(ticker)) {
      setWatchlist(watchlist.filter(t => t !== ticker));
    } else {
      setWatchlist([...watchlist, ticker]);
    }
  };

  const filterResults = () => {
    if (selectedFilter === 'all') return scanResults;
    if (selectedFilter === 'gapUp') return scanResults.filter(s => s.gapUp);
    if (selectedFilter === 'breakout') return scanResults.filter(s => s.breakout);
    if (selectedFilter === 'oversold') return scanResults.filter(s => s.oversold);
    return scanResults;
  };

  const handleChartMouseDown = (e) => {
    if (!drawMode) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setStartPoint({ x, y });
    setIsDrawing(true);
  };

  const handleChartMouseMove = (e) => {
    if (!isDrawing || !startPoint || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const currentX = e.clientX - rect.left;
    const currentY = e.clientY - rect.top;

    const ctx = canvas.getContext('2d');
    canvas.width = canvas.offsetWidth;
    canvas.height = canvas.offsetHeight;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Redraw previous lines
    lines.forEach(line => {
      ctx.strokeStyle = line.color;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(line.x1, line.y1);
      ctx.lineTo(line.x2, line.y2);
      ctx.stroke();
    });

    // Draw current line
    ctx.strokeStyle = drawMode === 'trendline' ? '#10b981' : '#f59e0b';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(startPoint.x, startPoint.y);
    ctx.lineTo(currentX, currentY);
    ctx.stroke();
  };

  const handleChartMouseUp = (e) => {
    if (!isDrawing || !startPoint || !canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const endX = e.clientX - rect.left;
    const endY = e.clientY - rect.top;

    const newLine = {
      x1: startPoint.x,
      y1: startPoint.y,
      x2: endX,
      y2: endY,
      color: drawMode === 'trendline' ? '#10b981' : '#f59e0b',
      type: drawMode
    };

    setLines([...lines, newLine]);
    setIsDrawing(false);
    setStartPoint(null);

    // Redraw canvas
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    [...lines, newLine].forEach(line => {
      ctx.strokeStyle = line.color;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(line.x1, line.y1);
      ctx.lineTo(line.x2, line.y2);
      ctx.stroke();
    });
  };

  const clearDrawing = () => {
    setLines([]);
    if (canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      ctx.clearRect(0, 0, canvas.width, canvas.height);
    }
  };

  if (page === 'landing') {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0a0e27 0%, #1a1f3a 100%)', minHeight: '100vh', color: 'white' }}>
        <nav style={{ padding: '1.5rem 2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid rgba(148,163,184,0.1)' }}>
          <h1 style={{ margin: 0, fontSize: '32px', fontWeight: 'bold', background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>Bailey's Gauge</h1>
          <div style={{ display: 'flex', gap: '1rem' }}>
            <button onClick={() => { setIsSignUp(false); setPage('auth'); }} style={{ padding: '0.75rem 1.5rem', background: 'transparent', color: '#10b981', border: '2px solid #10b981', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>Sign In</button>
            <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '0.75rem 1.5rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>Sign Up</button>
          </div>
        </nav>
        <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '4rem 2rem', textAlign: 'center' }}>
          <h2 style={{ fontSize: '56px', fontWeight: 'bold', marginBottom: '1rem' }}>Day Trading Scanner with Drawing Tools</h2>
          <p style={{ fontSize: '20px', color: '#94a3b8', marginBottom: '2rem' }}>Professional-grade tools for day traders. Draw support/resistance. Real-time signals. Better than AskLivemore.</p>
          <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '1rem 3rem', background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', fontSize: '18px' }}>Get Started Free</button>
        </div>
      </div>
    );
  }

  if (page === 'auth') {
    return (
      <div style={{ padding: '2rem', textAlign: 'center', background: 'linear-gradient(135deg, #0a0e27 0%, #1a1f3a 100%)', color: 'white', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ maxWidth: '400px', width: '100%', background: 'rgba(30,41,59,0.9)', padding: '2rem', borderRadius: '12px', border: '1px solid rgba(148,163,184,0.2)' }}>
          <h2 style={{ marginBottom: '2rem' }}>{isSignUp ? 'Create Account' : 'Sign In'}</h2>
          <form onSubmit={handleAuth}>
            {isSignUp && <input type="text" placeholder="Name" value={name} onChange={(e) => setName(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none', background: 'rgba(15,23,42,0.7)', color: 'white' }} required />}
            <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none', background: 'rgba(15,23,42,0.7)', color: 'white' }} required />
            <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none', background: 'rgba(15,23,42,0.7)', color: 'white' }} required />
            <button type="submit" style={{ width: '100%', padding: '0.75rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>{loading ? 'Loading...' : (isSignUp ? 'Sign Up' : 'Sign In')}</button>
          </form>
          <p style={{ marginTop: '1rem', color: '#94a3b8' }}>{isSignUp ? 'Have account?' : 'No account?'} <button onClick={() => setIsSignUp(!isSignUp)} style={{ background: 'none', border: 'none', color: '#10b981', cursor: 'pointer', fontWeight: 'bold' }}>{isSignUp ? 'Sign In' : 'Sign Up'}</button></p>
          <button onClick={() => setPage('landing')} style={{ width: '100%', marginTop: '1rem', padding: '0.75rem', background: 'transparent', color: '#94a3b8', border: '1px solid rgba(148,163,184,0.2)', borderRadius: '8px', cursor: 'pointer' }}>Back</button>
        </div>
      </div>
    );
  }

  if (page === 'app' && isLoggedIn) {
    const filtered = filterResults();
    return (
      <div style={{ background: 'linear-gradient(135deg, #0a0e27 0%, #1a1f3a 100%)', minHeight: '100vh', color: 'white' }}>
        <nav style={{ background: 'rgba(10,14,39,0.8)', borderBottom: '1px solid rgba(148,163,184,0.1)', padding: '1rem 2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h1 style={{ margin: 0, fontSize: '24px', fontWeight: 'bold', color: '#10b981' }}>Bailey's Gauge</h1>
          <div style={{ display: 'flex', gap: '2rem', alignItems: 'center' }}>
            <div style={{ display: 'flex', gap: '1rem' }}>
              <button onClick={() => setActiveTab('screener')} style={{ background: activeTab === 'screener' ? '#10b981' : 'transparent', color: 'white', border: activeTab === 'screener' ? 'none' : '1px solid rgba(148,163,184,0.2)', padding: '0.5rem 1rem', borderRadius: '6px', cursor: 'pointer', fontWeight: activeTab === 'screener' ? 'bold' : 'normal' }}>Screener</button>
              <button onClick={() => setActiveTab('watchlist')} style={{ background: activeTab === 'watchlist' ? '#10b981' : 'transparent', color: 'white', border: activeTab === 'watchlist' ? 'none' : '1px solid rgba(148,163,184,0.2)', padding: '0.5rem 1rem', borderRadius: '6px', cursor: 'pointer', fontWeight: activeTab === 'watchlist' ? 'bold' : 'normal' }}>Watchlist ({watchlist.length})</button>
            </div>
            <button onClick={() => { localStorage.removeItem('token'); setIsLoggedIn(false); setPage('landing'); }} style={{ padding: '0.5rem 1rem', background: '#ef4444', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold' }}>Logout</button>
          </div>
        </nav>

        <div style={{ maxWidth: '1600px', margin: '0 auto', padding: '2rem' }}>
          {activeTab === 'screener' && (
            <>
              <div style={{ background: 'rgba(30,41,59,0.6)', padding: '2rem', borderRadius: '12px', border: '1px solid rgba(148,163,184,0.1)', marginBottom: '2rem' }}>
                <form onSubmit={handleScan} style={{ display: 'flex', gap: '1rem', marginBottom: '1.5rem' }}>
                  <input type="text" value={scanInput} onChange={(e) => setScanInput(e.target.value)} placeholder="AAPL,MSFT,GOOGL,TSLA..." style={{ flex: 1, padding: '0.75rem', borderRadius: '8px', border: 'none', background: 'rgba(15,23,42,0.7)', color: 'white' }} />
                  <button type="submit" disabled={loading} style={{ padding: '0.75rem 2rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>{loading ? 'Scanning...' : 'Scan'}</button>
                </form>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.5rem' }}>
                {filtered.map((stock, i) => (
                  <div key={i} onClick={() => { setSelectedStock(stock); setChartData(generateChartData()); setLines([]); }} style={{ background: 'rgba(30,41,59,0.6)', padding: '1.5rem', borderRadius: '12px', border: selectedStock?.ticker === stock.ticker ? '2px solid #10b981' : '1px solid rgba(148,163,184,0.1)', cursor: 'pointer' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '1rem' }}>
                      <h3 style={{ margin: 0, fontSize: '20px', color: '#10b981' }}>{stock.ticker}</h3>
                      <button onClick={(e) => { e.stopPropagation(); toggleWatchlist(stock.ticker); }} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '20px', color: watchlist.includes(stock.ticker) ? '#ef4444' : '#94a3b8' }}>❤️</button>
                    </div>
                    <p style={{ margin: '0.5rem 0', color: stock.change > 0 ? '#10b981' : '#ef4444', fontWeight: 'bold' }}>{stock.change > 0 ? '▲' : '▼'} {stock.change}%</p>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem', marginTop: '1rem' }}>
                      {stock.gapUp && <span style={{ background: '#10b981', color: 'white', padding: '0.25rem 0.5rem', borderRadius: '4px', fontSize: '11px' }}>Gap Up</span>}
                      {stock.breakout && <span style={{ background: '#f59e0b', color: 'white', padding: '0.25rem 0.5rem', borderRadius: '4px', fontSize: '11px' }}>Breakout</span>}
                    </div>
                  </div>
                ))}
              </div>

              {selectedStock && (
                <div style={{ marginTop: '3rem', background: 'rgba(30,41,59,0.6)', padding: '2rem', borderRadius: '12px', border: '1px solid rgba(148,163,184,0.1)' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                    <h2 style={{ color: '#10b981', margin: 0 }}>{selectedStock.ticker} - 24H Chart</h2>
                    <div style={{ display: 'flex', gap: '0.75rem' }}>
                      <button onClick={() => setDrawMode(drawMode === 'trendline' ? null : 'trendline')} style={{ padding: '0.5rem 1rem', background: drawMode === 'trendline' ? '#10b981' : 'rgba(15,23,42,0.5)', color: 'white', border: '1px solid rgba(148,163,184,0.2)', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold' }}>📈 Trendline</button>
                      <button onClick={() => setDrawMode(drawMode === 'support' ? null : 'support')} style={{ padding: '0.5rem 1rem', background: drawMode === 'support' ? '#f59e0b' : 'rgba(15,23,42,0.5)', color: 'white', border: '1px solid rgba(148,163,184,0.2)', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold' }}>📊 Support/Resist</button>
                      <button onClick={clearDrawing} style={{ padding: '0.5rem 1rem', background: '#ef4444', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold' }}>🗑️ Clear</button>
                    </div>
                  </div>

                  <div style={{ position: 'relative', background: 'rgba(15,23,42,0.5)', borderRadius: '12px', overflow: 'hidden', marginBottom: '2rem' }}>
                    <ResponsiveContainer width="100%" height={400}>
                      <LineChart data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" stroke="rgba(148,163,184,0.1)" />
                        <XAxis dataKey="time" stroke="#94a3b8" style={{ fontSize: '12px' }} />
                        <YAxis stroke="#94a3b8" style={{ fontSize: '12px' }} />
                        <Tooltip contentStyle={{ background: 'rgba(15,23,42,0.95)', border: '1px solid rgba(148,163,184,0.2)', borderRadius: '8px', color: 'white' }} />
                        <Line type="monotone" dataKey="price" stroke="#10b981" strokeWidth={2} dot={false} />
                      </LineChart>
                    </ResponsiveContainer>
                    <canvas
                      ref={canvasRef}
                      onMouseDown={handleChartMouseDown}
                      onMouseMove={handleChartMouseMove}
                      onMouseUp={handleChartMouseUp}
                      onMouseLeave={handleChartMouseUp}
                      style={{ position: 'absolute', top: 0, left: 0, cursor: drawMode ? 'crosshair' : 'default', display: 'block' }}
                      width={800}
                      height={400}
                    />
                  </div>

                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '1rem' }}>
                    <div style={{ background: 'rgba(15,23,42,0.5)', padding: '1rem', borderRadius: '8px' }}>
                      <p style={{ color: '#94a3b8', margin: '0 0 0.5rem', fontSize: '12px' }}>Price</p>
                      <p style={{ color: 'white', fontSize: '20px', margin: 0, fontWeight: 'bold' }}>${selectedStock.price}</p>
                    </div>
                    <div style={{ background: 'rgba(15,23,42,0.5)', padding: '1rem', borderRadius: '8px' }}>
                      <p style={{ color: '#94a3b8', margin: '0 0 0.5rem', fontSize: '12px' }}>RSI</p>
                      <p style={{ color: selectedStock.rsi > 70 ? '#ef4444' : selectedStock.rsi < 30 ? '#10b981' : 'white', fontSize: '20px', margin: 0, fontWeight: 'bold' }}>{selectedStock.rsi}</p>
                    </div>
                  </div>

                  {drawMode && <p style={{ marginTop: '1rem', color: '#94a3b8', fontSize: '12px' }}>💡 Click and drag on chart to draw {drawMode === 'trendline' ? 'trendline' : 'support/resistance'}</p>}
                </div>
              )}
            </>
          )}

          {activeTab === 'watchlist' && (
            <div>
              {watchlist.length === 0 ? (
                <p style={{ color: '#94a3b8', textAlign: 'center', padding: '4rem' }}>No stocks in watchlist</p>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '1rem' }}>
                  {scanResults.filter(s => watchlist.includes(s.ticker)).map((stock, i) => (
                    <div key={i} style={{ background: 'rgba(30,41,59,0.6)', padding: '1.5rem', borderRadius: '12px', border: '1px solid rgba(148,163,184,0.1)' }}>
                      <h3 style={{ margin: '0 0 1rem', color: '#10b981' }}>{stock.ticker}</h3>
                      <p style={{ color: stock.change > 0 ? '#10b981' : '#ef4444', fontWeight: 'bold', margin: '0.5rem 0' }}>{stock.change > 0 ? '▲' : '▼'} {stock.change}%</p>
                      <button onClick={() => toggleWatchlist(stock.ticker)} style={{ marginTop: '1rem', padding: '0.5rem 1rem', background: '#ef4444', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold', width: '100%' }}>Remove</button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    );
  }

  return null;
};

export default App;
